-func engineWithBusyRetry(op func() error) error {
-	const maxAttempts = 6
-	backoff := 10 * time.Millisecond
-	var lastErr error
-	for attempt := 1; attempt <= maxAttempts; attempt++ {
-		err := op()
-		if err == nil {
-			return nil
-		}
-		if !engineIsBusyLockError(err) {
-			return err
-		}
-		lastErr = err
-		if attempt < maxAttempts {
-			time.Sleep(backoff)
-			backoff *= 2
-		}
-	}
-	return lastErr
-}
