+func TestIsValidIDSuffix(t *testing.T) {
+	tests := []struct {
+		s    string
+		want bool
+	}{
+		// Numeric suffixes (traditional)
+		{"123", true},
+		{"0", true},
+		{"999", true},
+		// Hash-based suffixes (base36: 0-9, a-z)
+		{"a3f8e9", true},
+		{"09ea", true},
+		{"abc123", true},
+		{"zzz", true},
+		// Hierarchical suffixes (hash.number format)
+		{"6we.2", true},
+		{"abc.1", true},
+		{"abc.1.2", true},
+		{"abc.1.2.3", true},
+		{"1.5", true},
