+	if err := store.ClaimIssue(ctx, issue.ID, "claiming-agent"); err != nil {
+		t.Fatalf("ClaimIssue failed: %v", err)
+	}
+
+	// Verify issue is now dirty
+	dirtyIssues, err = store.GetDirtyIssues(ctx)
+	if err != nil {
+		t.Fatalf("GetDirtyIssues failed: %v", err)
+	}
+	found := false
+	for _, id := range dirtyIssues {
+		if id == issue.ID {
+			found = true
+			break
+		}
+	}
+	if !found {
+		t.Error("expected issue to be marked dirty after claim")
+	}
+}

