+
+	// Add comments with identifiable ordering
+	for i := 1; i <= 5; i++ {
+		text := "Comment " + strconv.Itoa(i)
+		_, err := store.AddIssueComment(ctx, issue.ID, "alice", text)
+		if err != nil {
+			t.Fatalf("AddIssueComment failed: %v", err)
+		}
+	}
